                    <span data-v="2" onclick="pickStar(2)">★</span>
                    <span data-v="3" onclick="pickStar(3)">★</span>
                    <span data-v="4" onclick="pickStar(4)">★</span>
                    <span data-v="5" onclick="pickStar(5)">★</span>
                </div>

                <div class="mb-3">
                    <label class="form-label" style="font-size:13px;font-weight:600">Name</label>
                    <input type="text" class="form-control" id="rName" placeholder="Your name" />
