<script src="https://cdn.jsdelivr.net/npm/bootstrap@5.3.2/dist/js/bootstrap.bundle.min.js"></script>
<script>
    // ── Star picker ──
    let pickedStars = 0;

    function pickStar(n) {
        pickedStars = n;
        document.querySelectorAll('#starPicker span').forEach((s, i) => {
            s.classList.toggle('lit', i < n);
        });
    }

    // ── Submit Review ──
    function submitReview() {
        const name = document.getElementById('rName').value.trim();
        const skin = document.getElementById('rSkin').value;
        const title = document.getElementById('rTitle').value.trim();
        const body = document.getElementById('rBody').value.trim();
        const err = document.getElementById('rError');

        if (!name || !title || !body || pickedStars === 0) {
            err.style.display = 'block';
            return;
        }
        err.style.display = 'none';

        const starStr = '★'.repeat(pickedStars) + (pickedStars < 5 ? '<span style="color:#ddd">' + '★'.repeat(5 - pickedStars) + '</span>' : '');
        const skinLine = skin ? `<span>Skin Type: ${skin}</span>` : '';

        const card = document.createElement('div');
        card.className = 'review-card';
        card.dataset.helpful = '0';
        card.dataset.rating = pickedStars;
        card.dataset.date = new Date().toISOString().slice(0, 10);
        card.innerHTML = `
      <div class="row g-0">
        <div class="col-12 col-sm-3 col-md-2 mb-3 mb-sm-0">
          <div class="reviewer-name">${escHtml(name)}</div>
          <div class="reviewer-meta">${skinLine}</div>
        </div>
        <div class="col-12 col-sm-9 col-md-10 ps-sm-3">
          <div class="review-stars">${starStr}</div>
          <div class="review-title">${escHtml(title)}</div>
          <div class="review-body">${escHtml(body)}</div>
          <div class="vote-row">
            <button class="vote-btn" onclick="likeReview(this)">
              <i class="fa fa-thumbs-up"></i> <span class="vote-num">0</span>
            </button>
            <button class="vote-btn dislike-btn">
              <i class="fa fa-thumbs-down"></i> <span class="vote-num">0</span>
            </button>
          </div>
        </div>
      </div>`;

        document.getElementById('reviewList').prepend(card);

        // reset
        ['rName', 'rTitle', 'rBody'].forEach(id => document.getElementById(id).value = '');
        document.getElementById('rSkin').value = '';
        pickStar(0);
        bootstrap.Modal.getInstance(document.getElementById('rateModal')).hide();
    }

    // ── Like/Dislike ──
    function likeReview(btn) {
        if (btn.classList.contains('liked')) {
            btn.classList.remove('liked');
            const n = btn.querySelector('.vote-num');
            n.textContent = Math.max(0, parseInt(n.textContent) - 1);
        } else {
            btn.classList.add('liked');
            const n = btn.querySelector('.vote-num');
            n.textContent = parseInt(n.textContent) + 1;
        }
    }

    // ── Sort reviews ──
    function sortReviews() {
        const val = document.getElementById('sortSelect').value;
        const list = document.getElementById('reviewList');
        const cards = Array.from(list.querySelectorAll('.review-card'));

        cards.sort((a, b) => {
            if (val === 'helpful') return parseInt(b.dataset.helpful) - parseInt(a.dataset.helpful);
            if (val === 'recent') return b.dataset.date.localeCompare(a.dataset.date);
            if (val === 'high') return parseInt(b.dataset.rating) - parseInt(a.dataset.rating);
            if (val === 'low') return parseInt(a.dataset.rating) - parseInt(b.dataset.rating);
        });

        cards.forEach(c => {
            c.style.animation = 'none';
            list.appendChild(c);
        });
        requestAnimationFrame(() => {
            cards.forEach(c => {
                c.style.animation = '';
                c.style.animationName = 'fadeSlideIn';
            });
        });
    }

    // ── Ask Question ──
    function openAskForm() {
        const f = document.getElementById('askFormWrap');
        f.style.display = 'block';
        f.scrollIntoView({
            behavior: 'smooth',
            block: 'start'
        });
    }

    function closeAskForm() {
        document.getElementById('askFormWrap').style.display = 'none';
        document.getElementById('qError').style.display = 'none';
        document.getElementById('qName').value = '';
        document.getElementById('qText').value = '';
    }
    document.getElementById('openAskForm').addEventListener('click', openAskForm);
    document.getElementById('openAskForm2').addEventListener('click', openAskForm);

    function submitQuestion() {
        const name = document.getElementById('qName').value.trim();
        const text = document.getElementById('qText').value.trim();
        const err = document.getElementById('qError');

        if (!name || !text) {
            err.style.display = 'block';
            return;
        }
        err.style.display = 'none';

        const initials = name.split(' ').map(w => w[0].toUpperCase()).join('').slice(0, 2);

        const now = new Date();
        const timeLabel = 'Just now';

        const card = document.createElement('div');
        card.className = 'question-card';
        card.innerHTML = `
      <div class="question-header">
        <div class="q-avatar">${initials}</div>
        <div>
          <div class="q-patient-label">
            <span class="q-badge"><i class="fa fa-user-injured" style="font-size:9px"></i> Patient asking question</span>
          </div>
          <div class="q-name">${escHtml(name)}</div>
        </div>
        <div class="q-time">${timeLabel}</div>
      </div>
      <div class="q-text">${escHtml(text)}</div>`;

        const qaList = document.getElementById('qaList');
        qaList.prepend(card);

        closeAskForm();
        card.scrollIntoView({
            behavior: 'smooth',
            block: 'center'
        });
    }

    // ── Escape HTML ──
    function escHtml(str) {
        return str.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
            .replace(/"/g, '&quot;').replace(/'/g, '&#39;');
    }
</script>

