            label: "Badge",
            svg: `<svg xmlns="./assets/img/sample1.png" viewBox="0 0 220 220">
        <rect width="220" height="220" fill="#f8f4f0"/>
        <circle cx="110" cy="110" r="80" fill="none" stroke="#b01b2e" stroke-width="3"/>
        <text x="110" y="90" font-family="Arial" font-size="12" font-weight="bold" fill="#b01b2e" text-anchor="middle">NEW GEN</text>
        <text x="110" y="110" font-family="Arial" font-size="10" fill="#333" text-anchor="middle">UV FILTERS</text>
        <text x="110" y="130" font-family="Arial" font-size="9" fill="#666" text-anchor="middle">European Standard</text>
      </svg>`
        }
    ];

    let currentIndex = 0;

    // Convert SVG string to data URL
    function svgToDataUrl(svgStr) {
        return 'data:image/svg+xml;charset=utf-8,' + encodeURIComponent(svgStr);
    }

    // Build thumbnails
    const thumbCol = document.getElementById('thumbCol');
    images.forEach((img, i) => {
        const div = document.createElement('div');
        div.className = 'thumb-item' + (i === 0 ? ' active' : '');
        div.innerHTML = `<img src="${svgToDataUrl(img.svg)}" alt="${img.label}"/>`;
        div.addEventListener('click', () => setImage(i));
        thumbCol.appendChild(div);
    });

    const mainImg = document.getElementById('mainImg');

    function setImage(index) {
        currentIndex = (index + images.length) % images.length;
        mainImg.style.opacity = '0';
        setTimeout(() => {
            mainImg.src = svgToDataUrl(images[currentIndex].svg);
            mainImg.alt = images[currentIndex].label;
            mainImg.style.opacity = '1';
        }, 150);
        // Update thumb highlights
        document.querySelectorAll('.thumb-item').forEach((t, i) => {
            t.classList.toggle('active', i === currentIndex);
        });
    }

    // Init first image
    setImage(0);

    // Arrow controls
    document.getElementById('arrowLeft').addEventListener('click', () => setImage(currentIndex - 1));
    document.getElementById('arrowRight').addEventListener('click', () => setImage(currentIndex + 1));

    // Tab switching
    function switchTab(el, id) {
        document.querySelectorAll('.info-tab').forEach(t => t.classList.remove('active'));
        el.classList.add('active');
        ['desc', 'how', 'other'].forEach(tid => {
            document.getElementById('tab-' + tid).style.display = tid === id ? '' : 'none';
        });
    }
</script>


